const immutable = {
  setIn(obj, path, value) {
    const keys = path.split('.');
    const result = { ...obj };
    let current = result;
    for (let i = 0; i < keys.length - 1; i++) {
      current[keys[i]] = Array.isArray(current[keys[i]]) 
        ? [...current[keys[i]]] : { ...current[keys[i]] };
      current = current[keys[i]];
    }
    current[keys[keys.length - 1]] = value;
    return result;
  },

  push(arr, ...items) { return [...arr, ...items]; },
  removeAt(arr, index) { return [...arr.slice(0, index), ...arr.slice(index + 1)]; },
  updateAt(arr, index, fn) { return arr.map((item, i) => i === index ? fn(item) : item); }
};

function createTransformStream(transformFn) {
  return new TransformStream({
    transform(chunk, controller) {
      const result = transformFn(chunk);
      if (result !== undefined) {
        controller.enqueue(result);
      }
    }
  });
}

